+            FieldType::String => {
+                let raw: Option<String> = row.get(idx)?;
+                raw.map(FieldValue::String).unwrap_or(FieldValue::Null)
+            }
+            FieldType::Integer => {
+                let raw: Option<i64> = row.get(idx)?;
+                raw.map(FieldValue::Integer).unwrap_or(FieldValue::Null)
+            }
+        };
+        out.push((field.clone(), value));
