+fn csv_escape(value: &str) -> String {
+    if value.is_empty() {
+        return String::new();
+    }
+    let needs_quotes = value.contains(',')
+        || value.contains('"')
+        || value.contains('\n')
+        || value.contains('\r');
+    if needs_quotes {
+        let escaped = value.replace('"', "\"\"");
+        format!("\"{}\"", escaped)
+    } else {
+        value.to_string()
+    }
+}
