+    if let Some(output_path) = path {
+        let file = fs::File::create(output_path)
+            .map_err(|e| format!("Failed to create output file: {}", e))?;
+        Ok(Box::new(BufWriter::new(file)))
+    } else {
+        Ok(Box::new(BufWriter::new(std::io::stdout())))
+    }
+}
